/// <summary>
/// Enables date field related to aging period.
/// </summary>
/// <param name="_periodUnit">
/// A value index of enum <c>InventAgingPeriod</c> indicating the aging period selected.
/// </param>
protected void enableAgingGroups(InventAgingPeriod _periodUnit)
{
    dialogFieldAgingDaysOne.visible(_periodUnit == InventAgingPeriod::Days);
    dialogFieldAgingDaysTwo.visible(_periodUnit == InventAgingPeriod::Days);
    dialogFieldAgingDaysThree.visible(_periodUnit == InventAgingPeriod::Days);
    dialogFieldAgingDaysFour.visible(_periodUnit == InventAgingPeriod::Days);
    dialogFieldAgingDaysFive.visible(_periodUnit == InventAgingPeriod::Days);
    dialogFieldAgingDaysSix.visible(_periodUnit == InventAgingPeriod::Days);

    dialogFieldAgingDatesOne.visible(_periodUnit == InventAgingPeriod::Dates);
    dialogFieldAgingDatesTwo.visible(_periodUnit == InventAgingPeriod::Dates);
    dialogFieldAgingDatesThree.visible(_periodUnit == InventAgingPeriod::Dates);
    dialogFieldAgingDatesFour.visible(_periodUnit == InventAgingPeriod::Dates);
    dialogFieldAgingDatesFive.visible(_periodUnit == InventAgingPeriod::Dates);
    dialogFieldAgingDatesSix.visible(_periodUnit == InventAgingPeriod::Dates);

    dialogFieldAgingDatePeriodOne.visible(_periodUnit == InventAgingPeriod::DateIntervals);
    dialogFieldAgingDatePeriodTwo.visible(_periodUnit == InventAgingPeriod::DateIntervals);
    dialogFieldAgingDatePeriodThree.visible(_periodUnit == InventAgingPeriod::DateIntervals);
    dialogFieldAgingDatePeriodFour.visible(_periodUnit == InventAgingPeriod::DateIntervals);
    dialogFieldAgingDatePeriodFive.visible(_periodUnit == InventAgingPeriod::DateIntervals);
    dialogFieldAgingDatePeriodSix.visible(_periodUnit == InventAgingPeriod::DateIntervals);
}

/// <summary>
/// Registers method override in order to capture dialog events.
/// </summary>
public void postRun()
{
    super();

    dialog.dialogForm().formRun().controlMethodOverload(false);

    dialogFieldAgingPeriodUnit.registerOverrideMethod(#SelectionChangeMethodName, methodStr(ETG_InventAgingStorageUIBuilder, selectionChangeAging), this);
    dialogFieldAgingDaysOne.registerOverrideMethod(#ValidateMethodName, methodStr(ETG_InventAgingStorageUIBuilder, validateDays), this);
    dialogFieldAgingDaysTwo.registerOverrideMethod(#ValidateMethodName, methodStr(ETG_InventAgingStorageUIBuilder, validateDays), this);
    dialogFieldAgingDaysThree.registerOverrideMethod(#ValidateMethodName, methodStr(ETG_InventAgingStorageUIBuilder, validateDays), this);
    dialogFieldAgingDaysFour.registerOverrideMethod(#ValidateMethodName, methodStr(ETG_InventAgingStorageUIBuilder, validateDays), this);
    dialogFieldAgingDaysFive.registerOverrideMethod(#ValidateMethodName, methodStr(ETG_InventAgingStorageUIBuilder, validateDays), this);
    dialogFieldAgingDaysSix.registerOverrideMethod(#ValidateMethodName, methodStr(ETG_InventAgingStorageUIBuilder, validateDays), this);
}

/// <summary>
/// This method initializes the dialog fields after the fields have been built.
/// </summary>
public void postBuild()
{
    dialogFieldAgingPeriodUnit = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETG_InventAgingStorageContract, parmAgingPeriodUnit));

    dialogFieldAgingDaysOne = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETG_InventAgingStorageContract, parmIntervalDaysOne));
    dialogFieldAgingDaysTwo = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETG_InventAgingStorageContract, parmIntervalDaysTwo));
    dialogFieldAgingDaysThree = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETG_InventAgingStorageContract, parmIntervalDaysThree));
    dialogFieldAgingDaysFour = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETG_InventAgingStorageContract, parmIntervalDaysFour));
    dialogFieldAgingDaysFive = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETG_InventAgingStorageContract, parmIntervalDaysFive));
    dialogFieldAgingDaysSix  = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETG_InventAgingStorageContract, parmIntervalDaysSix));

    dialogFieldAgingDatesOne = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETG_InventAgingStorageContract, parmIntervalDateOne));
    dialogFieldAgingDatesTwo = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETG_InventAgingStorageContract, parmIntervalDateTwo));
    dialogFieldAgingDatesThree = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETG_InventAgingStorageContract, parmIntervalDateThree));
    dialogFieldAgingDatesFour = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETG_InventAgingStorageContract, parmIntervalDateFour));
    dialogFieldAgingDatesFive = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETG_InventAgingStorageContract, parmIntervalDateFive));
    dialogFieldAgingDatesSix = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETG_InventAgingStorageContract, parmIntervalDateSix));


    dialogFieldAgingDatePeriodOne = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETG_InventAgingStorageContract, parmIntervalDatePeriodOne));
    dialogFieldAgingDatePeriodTwo = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETG_InventAgingStorageContract, parmIntervalDatePeriodTwo));
    dialogFieldAgingDatePeriodThree = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETG_InventAgingStorageContract, parmIntervalDatePeriodThree));
    dialogFieldAgingDatePeriodFour = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETG_InventAgingStorageContract, parmIntervalDatePeriodFour));
    dialogFieldAgingDatePeriodFive = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETG_InventAgingStorageContract, parmIntervalDatePeriodFive));
    dialogFieldAgingDatePeriodSix = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETG_InventAgingStorageContract, parmIntervalDatePeriodSix));

    financialDimSet          = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(ETG_InventAgingStorageContract, parmFinancialDimSet));

    this.enableAgingGroups((this.dataContractObject() as ETG_InventAgingStorageContract).parmAgingPeriodUnit());

    super();
}

/// <summary>
/// Handles the aging period selection change event.
/// </summary>
/// <param name="_formControl">
/// The form control that raised the event.
/// </param>
/// <returns>
/// The changed selection.
/// </returns>
final protected int selectionChangeAging(FormComboBoxControl _formControl)
{
    int ret = _formControl.selectionChange();

    DictEnum dictEnum = new DictEnum(enumNum(InventAgingPeriod));
    this.enableAgingGroups(dictEnum.index2Value(_formControl.selection()));

    return ret;
}

/// <summary>
/// Handles the aging days validate event.
/// </summary>
/// <param name="_formControl">
/// The form control that raised the event.
/// </param>
/// <returns>
/// True if the days are greater or equals zero; otherwise false.
/// </returns>
protected boolean validateDays(FormIntControl   _formControl)
{
    boolean ret = _formControl.validate();

    if (ret && _formControl.value() < 0)
    {
        throw error("@SYS102923");
    }

    return ret;
}
